const tallyBody = $json.body || {};
const isTally = !!tallyBody.data?.fields;

function getField(label) {
  if (!isTally) return null;
  return tallyBody.data.fields.find(x => x.label && x.label.toLowerCase().includes(label.toLowerCase()));
}
function getValue(label, directKey) {
  const f = getField(label);
  if (f) {
    if (f.type === 'FILE_UPLOAD' && Array.isArray(f.value)) return f.value.map(v => v.url);
    if (Array.isArray(f.value)) return f.value;
    return f.value || '';
  }
  return tallyBody[directKey] !== undefined ? tallyBody[directKey] : '';
}

const imobiliaria = getValue('Nome da Imobiliária', 'imobiliaria') || '';
const logoArr = getValue('Logótipo da Imobiliária', 'logo');
const logoUrl = Array.isArray(logoArr) ? (logoArr[0] || '') : (logoArr || '');
const titulo = getValue('Título do Imóvel', 'titulo') || '';
const preco = getValue('Preço', 'preco') || '';
const tipologia = getValue('Tipologia', 'tipologia') || '';
const area = getValue('Área', 'area') || '';
const quartos = getValue('Quartos', 'quartos') || '';
const wc = getValue('WC', 'wc') || '';
const localizacao = getValue('Localização', 'localizacao') || '';
const fotosArr = getValue('Fotos do Imóvel', 'fotos');
const fotos = Array.isArray(fotosArr) ? fotosArr : (fotosArr ? [fotosArr] : []);
const videoUrl = getValue('Link do Vídeo', 'video_url') || '';
const destaque1 = getValue('Destaque 1', 'destaque1') || '';
const destaque2 = getValue('Destaque 2', 'destaque2') || '';
const destaque3 = getValue('Destaque 3', 'destaque3') || '';
const extrasArr = getValue('Extras', 'extras');
const extras = Array.isArray(extrasArr) ? extrasArr : (extrasArr ? [extrasArr] : []);
const ano = getValue('Ano de Construção', 'ano') || '';
const corretorNome = getValue('Nome do Corretor', 'corretor_nome') || '';
const corretorWhatsapp = getValue('WhatsApp do Corretor', 'corretor_whatsapp') || '';
const corretorEmail = getValue('Email do Corretor', 'corretor_email') || '';
const nif = getValue('NIF', 'nif') || '';

const imovel = {
  imobiliaria, logo: logoUrl, titulo, preco, tipologia, area, quartos, wc, localizacao,
  fotos, video_url: videoUrl,
  destaques_unicos: [destaque1, destaque2, destaque3].filter(Boolean),
  extras, ano, corretor: { nome: corretorNome, whatsapp: corretorWhatsapp, email: corretorEmail }, nif
};

// G1 -- validacao de entrada fail-loud: um campo obrigatorio vazio nunca deve
// produzir uma landing publicavel sem os dados do cliente (ver STATE.md).
// Opcionais (podem faltar em silencio): logo, video_url, extras, ano.
const REQUIRED_SIMPLE = {
  'Nome da Imobiliaria': imobiliaria,
  'Titulo do Imovel': titulo,
  'Preco': preco,
  'Tipologia': tipologia,
  'Area': area,
  'Quartos': quartos,
  'WC': wc,
  'Localizacao': localizacao,
  'Destaque 1': destaque1,
  'Destaque 2': destaque2,
  'Destaque 3': destaque3,
  'Nome do Corretor': corretorNome,
  'WhatsApp do Corretor': corretorWhatsapp,
  'Email do Corretor': corretorEmail,
  'NIF': nif
};
const camposEmFalta = Object.entries(REQUIRED_SIMPLE)
  .filter(([, v]) => String(v ?? '').trim() === '')
  .map(([label]) => label);
if (fotos.length < 4) camposEmFalta.push('Fotos do Imovel (minimo 4, recebidas ' + fotos.length + ')');
if (camposEmFalta.length) {
  throw new Error('VALIDACAO DE ENTRADA: campo(s) obrigatorio(s) vazio(s) ou ausente(s) -- ' +
    camposEmFalta.join(', ') + '. Execucao falhada antes de chamar o Gemini, nada publicado.');
}

let logoStatus = 'ausente';
let logoInlinePart = null;
let logoBase64 = '';
let logoMime = '';
if (logoUrl) {
  try {
    const res = await this.helpers.httpRequest({ url: logoUrl, encoding: 'arraybuffer' });
    logoBase64 = Buffer.from(res).toString('base64');
    logoMime = logoUrl.toLowerCase().endsWith('.png') ? 'image/png'
      : logoUrl.toLowerCase().endsWith('.svg') ? 'image/svg+xml'
      : logoUrl.toLowerCase().endsWith('.webp') ? 'image/webp' : 'image/jpeg';
    logoInlinePart = { inlineData: { mimeType: logoMime, data: logoBase64 } };
    logoStatus = 'presente, imagem fornecida';
  } catch (e) {
    logoStatus = 'ausente (falha ao descarregar)';
  }
}

return [{ json: { imovel_raw: imovel, logo_status: logoStatus, logo_base64: logoBase64, logo_mime: logoMime, logo_inline_part: logoInlinePart } }];

const FONT_POOL = [
  { display: 'Cormorant Garamond', body: 'Inter' },
  { display: 'Playfair Display', body: 'Source Sans 3' },
  { display: 'Fraunces', body: 'Work Sans' },
  { display: 'Libre Caslon Text', body: 'Karla' },
  { display: 'Marcellus', body: 'Mulish' }
];
const ARCHETYPE_POOL = ['cinematic', 'editorial', 'gallery_first'];
const BLACKLIST = 'imóvel de sonho, localização privilegiada, acabamentos de luxo, oportunidade única, excelente investimento, charme, requinte, sucesso, excelência';

const src = $items('Prepara Payload Diretor')[0].json;
const imovel = src.imovel_raw;

// Ledger: lido pelo no anterior "Le Variation Ledger" (falha tolerada -> sem binary)
let ledger = [];
try {
  if ($input.item.binary && $input.item.binary.ledger) {
    const buf = await this.helpers.getBinaryDataBuffer(0, 'ledger');
    ledger = JSON.parse(buf.toString('utf8'));
    if (!Array.isArray(ledger)) ledger = [];
  }
} catch (e) {
  ledger = [];
}
const ledgerRecent = ledger.slice(-5);

// Sinais objetivos que o Diretor deve considerar (nao sao regras rigidas, sao pistas)
const numFotos = (imovel.fotos || []).length;
const hasVideo = !!imovel.video_url;
const textoHistoricoRural = [(imovel.tipologia || ''), (imovel.titulo || ''), (imovel.localizacao || ''), (imovel.ano || '')].join(' ').toLowerCase();
const pareceHistoricoRural = /quinta|herdade|rural|casal|restaurad|s[ée]culo|centen[aá]ri|lagar|azeite|monte\b/.test(textoHistoricoRural);

const ledgerTexto = ledgerRecent.length
  ? ledgerRecent.map((l, i) => `${i + 1}. arquétipo="${l.arquetipo}", fontes="${l.par_fontes?.display} + ${l.par_fontes?.body}"`).join('\n')
  : '(vazio — esta é a primeira geração registada)';

const fontPoolTexto = FONT_POOL.map(f => `${f.display} + ${f.body}`).join('; ');

const promptText = `Atuas como Diretor de Arte de uma agência especializada em imobiliário de luxo em Portugal.
O teu papel é decidir a DIREÇÃO CRIATIVA de uma landing page para UM imóvel. Não escreves copy — isso é o Copywriter, que vai executar o teu brief a seguir.

DADOS DO IMÓVEL: ${JSON.stringify(imovel)}
LOGO: ${src.logo_status}

SINAIS DISPONÍVEIS (pistas, não regras rígidas — usa em conjunto com o teu critério):
- Tem vídeo promocional: ${hasVideo ? 'sim' : 'não'}
- Número de fotos: ${numFotos}
- Parece ter carácter histórico/rural pelo texto fornecido: ${pareceHistoricoRural ? 'sim' : 'não'}

HISTÓRICO DAS ÚLTIMAS GERAÇÕES (evitar repetição — ver regra 1 abaixo):
${ledgerTexto}

REGRAS:
1. PROIBIDO escolher a MESMA combinação de arquétipo + par de fontes de qualquer uma das gerações no histórico acima. Se o teu primeiro instinto colidir, escolhe a segunda melhor opção.
2. Arquétipo — orientação (não é if/else automático, pondera com o resto dos dados):
   - "cinematic": quando há vídeo e/ou fotos com grande impacto visual — hero full-screen imersivo.
   - "gallery_first": quando há muitas fotos (tipicamente 8 ou mais) mostrando espaços distintos — a grelha é o hero.
   - "editorial": quando o imóvel tem história, carácter ou raridade — composição assimétrica tipo revista de arquitetura.
3. Fontes: escolhe UM par do pool: ${fontPoolTexto}.
4. Paleta: se houver logo, deriva da marca; se não houver, escolhe pelo carácter do imóvel. PROIBIDO paletas default de startup (roxo/gradiente azul-rosa).
5. "angulo_headline" é a decisão mais importante que tomas. Define a TENSÃO emocional que o headline vai explorar — não pode ser um facto a parafrasear. Escolhe um destes ângulos e explica-o:
   - raridade: o que torna este imóvel quase impossível de repetir/encontrar.
   - contraste: a tensão entre dois opostos que coexistem no imóvel (ex: antigo vs. moderno, isolamento vs. proximidade).
   - promessa: a transformação de vida que o comprador ganha.
   - desejo: a inveja/aspiração que o imóvel provoca em quem o vê.
   Exemplo do nível de especificidade esperado: "explorar a raridade — quantas casas da Comporta têm o pôr do sol dentro da piscina?" NÃO escreves o headline em si — isso é o Copywriter.
6. "palavras_proibidas": indica exatamente 2 palavras ou expressões (além da lista negra padrão) que, dado o ângulo escolhido, tornariam o headline genérico se usadas. Ex.: se o ângulo é "raridade", proíbe "único" e "exclusivo" (batidas demais para esse ângulo).
7. Justifica arquétipo e paleta em 2-3 frases cada.
8. "espacamento": escolhe "arejado" (muito espaço em branco, respiração generosa — para imóveis serenos/isolados/minimalistas) ou "denso" (composição mais compacta, secções mais próximas — para imóveis urbanos/vibrantes com muito para mostrar).
9. "tratamento_imagem": escolhe "framed" (fotografia emoldurada — margem/moldura visível à volta da imagem, tratamento mais formal e contido) ou "full-bleed" (fotografia a sangrar até à margem do ecrã, tratamento mais imersivo). Não é o mesmo eixo que "espacamento" — podes ter imagens full-bleed num layout denso, ou emolduradas num layout arejado.
10. "ornamento": escolhe "nenhum" (sem elementos decorativos, só tipografia e espaço), "linha" (linhas finas divisórias entre secções) ou "marca" (um pequeno sinal/marca gráfica decorativa entre secções). Escolhe com moderação — o ornamento é a exceção, não a regra.

Lista negra padrão (o Copywriter também a vai receber): ${BLACKLIST}`;

const responseSchema = {
  type: 'OBJECT',
  required: ['conceito', 'angulo_headline', 'arquetipo', 'justificacao_arquetipo', 'paleta', 'justificacao_paleta', 'par_fontes', 'palavras_proibidas', 'espacamento', 'tratamento_imagem', 'ornamento'],
  properties: {
    conceito: { type: 'STRING' },
    angulo_headline: { type: 'STRING' },
    arquetipo: { type: 'STRING', enum: ARCHETYPE_POOL },
    justificacao_arquetipo: { type: 'STRING' },
    paleta: {
      type: 'OBJECT', required: ['bg', 'surface', 'ink', 'accent', 'accent_soft'],
      properties: { bg: { type: 'STRING' }, surface: { type: 'STRING' }, ink: { type: 'STRING' }, accent: { type: 'STRING' }, accent_soft: { type: 'STRING' } }
    },
    justificacao_paleta: { type: 'STRING' },
    par_fontes: {
      type: 'OBJECT', required: ['display', 'body'],
      properties: { display: { type: 'STRING' }, body: { type: 'STRING' } }
    },
    palavras_proibidas: { type: 'ARRAY', minItems: 2, maxItems: 2, items: { type: 'STRING' } },
    espacamento: { type: 'STRING', enum: ['arejado', 'denso'] },
    tratamento_imagem: { type: 'STRING', enum: ['framed', 'full-bleed'] },
    ornamento: { type: 'STRING', enum: ['nenhum', 'linha', 'marca'] }
  }
};

const parts = [{ text: promptText }];
if (src.logo_inline_part) parts.push(src.logo_inline_part);

const diretorRequest = {
  contents: [{ parts }],
  generationConfig: { temperature: 0.95, maxOutputTokens: 4096, responseMimeType: 'application/json', responseSchema }
};

return [{
  json: {
    diretorRequest,
    imovel_raw: imovel,
    logo_base64: src.logo_base64,
    logo_mime: src.logo_mime,
    ledger,
    font_pool: FONT_POOL,
    archetype_pool: ARCHETYPE_POOL
  }
}];

function hashStr(str, salt) {
  let h = 5381;
  const s = String(str) + '|' + salt;
  for (let i = 0; i < s.length; i++) {
    h = ((h << 5) + h + s.charCodeAt(i)) | 0;
  }
  return Math.abs(h);
}

const src = $items('Monta Prompt Diretor')[0].json;
const imovel = src.imovel_raw;
const ledger = src.ledger || [];
const FONT_POOL = src.font_pool;
const ARCHETYPE_POOL = src.archetype_pool;
const BLACKLIST = 'imóvel de sonho, localização privilegiada, acabamentos de luxo, oportunidade única, excelente investimento, charme, requinte, sucesso, excelência';

const DEFAULT_BRIEF = {
  conceito: 'Brief padrão (Diretor de Arte indisponível nesta execução) — apresentação sóbria e atemporal.',
  angulo_headline: 'promessa',
  arquetipo: 'editorial',
  justificacao_arquetipo: 'Brief de recurso: o arquétipo editorial funciona como base segura e sóbria quando não há uma decisão criativa disponível.',
  paleta: { bg: '#FAF8F5', surface: '#F1EDE6', ink: '#1C2421', accent: '#8C6D4F', accent_soft: '#E8DFD2' },
  justificacao_paleta: 'Brief de recurso: paleta neutra areia/terracota, segura para qualquer tipo de imóvel.',
  par_fontes: FONT_POOL[2],
  palavras_proibidas: ['fantástico', 'incrível'],
  espacamento: 'arejado',
  tratamento_imagem: 'framed',
  ornamento: 'linha'
};

// 1. Parse do Diretor — tolera falha (continueOnFail), aplica fallback documentado
let diretorFallback = false;
let diretorFallbackMotivo = '';
let brief = null;
try {
  const diretorItem = $items('Diretor de Arte')[0];
  if (diretorItem.json.error) throw new Error('Node HTTP falhou: ' + JSON.stringify(diretorItem.json.error).substring(0, 200));
  const cands = diretorItem.json.candidates;
  const parts = cands[0].content.parts;
  const raw = parts[parts.length - 1].text || '';
  const cleaned = raw.replace(/```json/g, '').replace(/```/g, '').trim();
  const parsed = JSON.parse(cleaned);
  const REQUIRED = ['conceito', 'angulo_headline', 'arquetipo', 'justificacao_arquetipo', 'paleta', 'justificacao_paleta', 'par_fontes', 'palavras_proibidas', 'espacamento', 'tratamento_imagem', 'ornamento'];
  for (const k of REQUIRED) { if (parsed[k] === undefined) throw new Error('campo "' + k + '" ausente na resposta do Diretor'); }
  brief = parsed;
} catch (e) {
  diretorFallback = true;
  diretorFallbackMotivo = e.message || String(e);
  brief = JSON.parse(JSON.stringify(DEFAULT_BRIEF));
  console.warn('DIRETOR DE ARTE: fallback ativado — ' + diretorFallbackMotivo);
}

// 2. Backstop — se a combinacao repetir qualquer uma das ultimas 3 do ledger, forca rotacao deterministica
const landingIdSeed = imovel.titulo + '|' + imovel.localizacao + '|' + Date.now();
const last3 = ledger.slice(-3);
const repeteUltimas3 = last3.some(l =>
  l.arquetipo === brief.arquetipo &&
  l.par_fontes?.display === brief.par_fontes?.display &&
  l.par_fontes?.body === brief.par_fontes?.body
);
let backstopAplicado = false;
if (repeteUltimas3) {
  backstopAplicado = true;
  const fontIdx = hashStr(landingIdSeed, 'font') % FONT_POOL.length;
  const archIdx = hashStr(landingIdSeed, 'arch') % ARCHETYPE_POOL.length;
  brief.par_fontes = FONT_POOL[fontIdx];
  brief.arquetipo = ARCHETYPE_POOL[archIdx];
  brief.justificacao_arquetipo += ' [Rotação automática aplicada: a escolha original repetia uma combinação recente.]';
}

// 3. Prompt do Copywriter — executa o brief, nao decide estetica
const destaquesUnicos = (imovel.destaques_unicos || []).filter(Boolean);
const numDestaquesObrigatorios = Math.max(destaquesUnicos.length, 1);
const numDestaquesMax = Math.max(5, numDestaquesObrigatorios + 2);
const numFotos = (imovel.fotos || []).length;
const listaDestaquesObrigatorios = destaquesUnicos.map((d, i) => `  ${i + 1}. ${d}`).join('\n');

const promptText = `Atuas como Copywriter de uma agência especializada em imobiliário de luxo em Portugal.
Executas o brief do Diretor de Arte abaixo. NÃO decides estética — arquétipo, paleta e fontes já estão decididos.

DADOS DO IMÓVEL: ${JSON.stringify(imovel)}

BRIEF DO DIRETOR DE ARTE:
- Conceito: ${brief.conceito}
- Ângulo do headline (a tensão a explorar): ${brief.angulo_headline}
- Arquétipo: ${brief.arquetipo}

INSTRUÇÃO CRÍTICA SOBRE O HEADLINE: o headline TEM de explorar o ângulo "${brief.angulo_headline}" definido pelo Diretor.
Se o headline for uma simples transcrição ou paráfrase de um dos destaques_unicos (ex: copiar literalmente "piscina de água salgada..." como headline), está ERRADO — isso é o que o Diretor foi contratado para evitar.
O headline deve usar um dos destaques_unicos como MATERIAL, não como frase pronta. A subheadline pode ser mais literal/descritiva.

INSTRUÇÃO CRÍTICA SOBRE OS DESTAQUES (imovel.destaques) — OBRIGATÓRIO:
O cliente submeteu estes ${numDestaquesObrigatorios} destaques_unicos (o que este imóvel tem que nenhum outro tem):
${listaDestaquesObrigatorios}
Cada um destes é OBRIGATÓRIO e gera um card na secção "02 A Casa", pela ordem dada acima — são os primeiros
${numDestaquesObrigatorios} itens do array "destaques". Em cada um desses itens, o campo "origem_destaque" TEM
de citar/parafrasear claramente qual dos destaques_unicos acima esse card desenvolve.
NÃO os substituas por comodidades genéricas (piscina, painéis solares, garagem, jardim, poço) — essas já estão
na ficha técnica, não são o argumento de venda único deste imóvel. Podes ACRESCENTAR cards extra DEPOIS destes
${numDestaquesObrigatorios} obrigatórios (até um total de ${numDestaquesMax}), nunca em vez deles.
Garante também que o pull-quote (descricao_lifestyle) não contradiz os destaques — se um destaque fala de
autenticidade histórica, a descricao_lifestyle não pode descrever algo genérico/moderno sem ligação a isso.

REGRAS:
1. Português europeu, sóbrio, sensorial.
2. PROIBIDO usar estas expressões ou emojis (lista negra padrão): ${BLACKLIST}.
3. PROIBIDO usar estas 2 palavras específicas definidas pelo Diretor para este imóvel: ${brief.palavras_proibidas.join(', ')}.
4. Preenche TODOS os campos do schema. Nenhum vazio.
5. Em "detalhe_unico_usado", indica qual dos destaques_unicos usaste como material do headline.
6. NÃO inventes nem reorganizes factos do imóvel (preço, tipologia, área, quartos, wc, ano,
   localização, extras) — esses campos são geridos deterministicamente pelo Compilador a partir
   dos dados originais, não fazem parte da tua resposta.
7. "galeria.legendas" tem de ter exatamente ${numFotos} legendas, uma por cada foto submetida, pela mesma ordem.
   Nenhuma legenda vazia.`;

const responseSchema = {
  type: 'OBJECT',
  required: ['detalhe_unico_usado', 'hero', 'imovel', 'galeria', 'localizacao', 'agendamento', 'seo'],
  properties: {
    detalhe_unico_usado: { type: 'STRING' },
    hero: { type: 'OBJECT', required: ['eyebrow', 'headline', 'subheadline', 'cta_label'],
      properties: { eyebrow: { type: 'STRING' }, headline: { type: 'STRING' }, subheadline: { type: 'STRING' }, cta_label: { type: 'STRING' } } },
    imovel: { type: 'OBJECT', required: ['descricao_lifestyle', 'destaques'],
      properties: {
        descricao_lifestyle: { type: 'STRING' },
        destaques: {
          type: 'ARRAY', minItems: numDestaquesObrigatorios, maxItems: numDestaquesMax,
          items: {
            type: 'OBJECT', required: ['titulo', 'descricao', 'origem_destaque'],
            properties: { titulo: { type: 'STRING' }, descricao: { type: 'STRING' }, origem_destaque: { type: 'STRING' } }
          }
        }
      } },
    galeria: { type: 'OBJECT', required: ['headline', 'legendas'],
      properties: { headline: { type: 'STRING' }, legendas: { type: 'ARRAY', minItems: numFotos, maxItems: numFotos, items: { type: 'STRING' } } } },
    localizacao: { type: 'OBJECT', required: ['headline', 'descricao_zona'], properties: { headline: { type: 'STRING' }, descricao_zona: { type: 'STRING' } } },
    agendamento: { type: 'OBJECT', required: ['headline', 'subtext', 'button_label'], properties: { headline: { type: 'STRING' }, subtext: { type: 'STRING' }, button_label: { type: 'STRING' } } },
    seo: { type: 'OBJECT', required: ['title', 'description'], properties: { title: { type: 'STRING' }, description: { type: 'STRING' } } }
  }
};

const parts = [{ text: promptText }];
if (src.logo_base64 && src.logo_mime) parts.push({ inlineData: { mimeType: src.logo_mime, data: src.logo_base64 } });

const copywriterRequest = {
  contents: [{ parts }],
  generationConfig: { temperature: 0.7, maxOutputTokens: 8192, responseMimeType: 'application/json', responseSchema }
};

return [{
  json: {
    copywriterRequest,
    imovel_raw: imovel,
    logo_base64: src.logo_base64,
    logo_mime: src.logo_mime,
    brief,
    ledger,
    diretor_fallback: diretorFallback,
    diretor_fallback_motivo: diretorFallbackMotivo,
    backstop_aplicado: backstopAplicado
  }
}];

// CONFIGURAÇÃO PRISMA — ponto único de alteração (acesso a $env está bloqueado
// no sandbox do Code node nesta instância n8n).
const PRISMA_CONTACT_WHATSAPP = '+351920000000';
const PRISMA_ATTRIBUTION_URL = 'https://prismastudio.pt';
const PRISMA_ATTRIBUTION_LABEL = 'Criado com Prisma';

function escapeHtml(unsafe) {
  if (unsafe === undefined || unsafe === null) return '';
  return String(unsafe).replace(/&/g, "&amp;").replace(/</g, "&lt;").replace(/>/g, "&gt;").replace(/"/g, "&quot;").replace(/'/g, "&#039;");
}
function escapeAttr(unsafe) {
  if (unsafe === undefined || unsafe === null) return '';
  return String(unsafe).replace(/"/g, "&quot;").replace(/'/g, "&#039;");
}
function safeUrl(unsafeUrl) {
  if (!unsafeUrl) return '';
  const u = String(unsafeUrl).trim();
  if (u.startsWith('http://') || u.startsWith('https://')) return escapeAttr(u);
  return '';
}
function toEmbedUrl(url) {
  if (!url) return '';
  const u = String(url).trim();
  let m = u.match(/(?:youtube\.com\/watch\?v=|youtu\.be\/|youtube\.com\/embed\/)([a-zA-Z0-9_-]{6,})/);
  if (m) return 'https://www.youtube.com/embed/' + m[1];
  m = u.match(/vimeo\.com\/(?:video\/)?(\d+)/);
  if (m) return 'https://player.vimeo.com/video/' + m[1];
  return '';
}
function toNumericPrice(str) {
  if (!str) return '';
  const digits = String(str).replace(/[^\d]/g, '');
  return digits || '';
}
function slugify(str) {
  return String(str || 'imovel').toLowerCase()
    .normalize('NFD').replace(/[̀-ͯ]/g, '')
