}
function isLowResImage(base64, mime) {
  try {
    const buf = Buffer.from(base64, 'base64');
    if (mime === 'image/png' && buf.length > 24 && buf.readUInt32BE(0) === 0x89504e47) {
      const width = buf.readUInt32BE(16);
      const height = buf.readUInt32BE(20);
      return width < 200 || height < 200;
    }
    if (mime === 'image/jpeg') {
      let i = 2;
      while (i < buf.length - 9) {
        if (buf[i] !== 0xFF) { i++; continue; }
        const marker = buf[i + 1];
        if (marker >= 0xC0 && marker <= 0xC3) {
          const height = buf.readUInt16BE(i + 5);
          const width = buf.readUInt16BE(i + 7);
          return width < 200 || height < 200;
        }
        const segLen = buf.readUInt16BE(i + 2);
        i += 2 + segLen;
      }
    }
  } catch (e) { /* formato não reconhecido (svg/webp) — não classifica como fraca */ }
  return false;
}
function renderLoop(html, key, items) {
  const escKey = key.replace('.', '\\.');
  const re = new RegExp('\\{\\{#' + escKey + '\\}\\}([\\s\\S]*?)\\{\\{\\/' + escKey + '\\}\\}');
  const m = html.match(re);
  if (!m) return html;
  const block = m[1];
  const rendered = (items || []).map(item => {
    let s = block;
    for (const k in item) {
      s = s.split('{{' + k + '}}').join(item[k]);
    }
    return s;
  }).join('');
  return html.replace(re, rendered);
}
function renderIf(html, key, condition) {
  const re = new RegExp('<!--IF:' + key + '-->([\\s\\S]*?)<!--/IF:' + key + '-->', 'g');
  return html.replace(re, condition ? '$1' : '');
}
function buildSrcsetAttr(url, widths, sizes) {
  const u = String(url || '');
  if (!u.startsWith('https://images.unsplash.com/')) return '';
  const base = u.split('?')[0];
  const parts = widths.map(w => `${base}?w=${w}&q=${w <= 800 ? 75 : 80}&auto=format ${w}w`);
  return `srcset="${escapeAttr(parts.join(', '))}" sizes="${escapeAttr(sizes)}"`;
}
function capitalizeFirst(str) {
  const s = String(str || '').trim();
  return s ? s.charAt(0).toUpperCase() + s.slice(1) : s;
}
function getInitials(name) {
  const stopwords = new Set(['de', 'da', 'do', 'das', 'dos', 'e', 'a', 'o', 'as', 'os']);
  // palavras genericas descritivas quando aparecem no INICIO do nome — a marca
  // costuma comecar depois delas (ex.: "Imobiliaria Sao Joao" -> a marca e "Sao Joao")
  const genericLeading = new Set(['imobiliaria', 'imobiliária', 'mediacao', 'mediação', 'agencia', 'agência', 'grupo', 'casa']);
  let words = String(name || '').trim().split(/\s+/).filter(Boolean);
  while (words.length > 1 && genericLeading.has(words[0].toLowerCase().replace(/[.,]/g, ''))) {
    words = words.slice(1);
  }
  words = words.filter(w => {
    const clean = w.replace(/[.,&]/g, '');
    return clean && !stopwords.has(clean.toLowerCase());
  });
  const initials = words.slice(0, 2).map(w => (w.replace(/[^\p{L}\p{N}]/gu, '')[0] || '').toUpperCase()).join('');
  return initials || String(name || 'P').charAt(0).toUpperCase();
}
function normalizeAccents(s) {
  return String(s || '').toLowerCase().normalize('NFD').replace(/[̀-ͯ]/g, '');
}
function keywordsOf(s) {
  const STOP = new Set(['de', 'da', 'do', 'das', 'dos', 'e', 'a', 'o', 'as', 'os', 'em', 'com', 'por', 'para', 'um', 'uma', 'uns', 'umas', 'no', 'na', 'nos', 'nas', 'ao', 'aos']);
  return normalizeAccents(s).replace(/[^a-z0-9\s]/g, ' ').split(/\s+/).filter(w => w.length >= 5 && !STOP.has(w));
}
