// comodidades genericas (o LLM nao inventa vocabulario identico por acaso).
function destaqueCobreOrigem(destaqueUnico, item) {
  const kws = keywordsOf(destaqueUnico);
  if (!kws.length) return true;
  const haystack = normalizeAccents((item && item.origem_destaque || '') + ' ' + (item && item.titulo || '') + ' ' + (item && item.descricao || ''));
  return kws.some(k => haystack.includes(k));
